package tracer

import (
	"crypto/md5"
	"encoding/hex"
	"fmt"
	"testing"
)

// TestParseClientHello_RealCurlCapture_PeetWS is the FULLY-EXTERNAL ground-truth
// check: a REAL curl 8.5.0 / OpenSSL 3.0.13 ClientHello captured off the wire
// (curl --trace) against tls.peet.ws on 2026-06-17, with reference fingerprints
// computed INDEPENDENTLY by peet.ws. Nothing here is generated by our code.
//
// JA3 matches peet.ws exactly. JA4 deliberately does NOT, and that is a FINDING:
// peet.ws (TrackMe) is non-compliant with the FoxIO JA4 spec — it drops the
// padding extension (0x0015) from the JA4_c hash, whereas the spec
// (technical_details/JA4.md: the padding extension "is NOT excluded") keeps it.
// peet reports JA4_c 375ca2c5e164; the FoxIO-correct value our spec-following
// ComputeJA4 produces is b26ce05bbdd6. The two differ ONLY by ext 0x0015 (proven
// by sha256'ing both lists). We assert the FoxIO-correct value. OPSEC/attribution
// caveat: peet.ws JA4 is NOT directly comparable to FoxIO/Wireshark JA4 when a
// padding extension is present.
func TestParseClientHello_RealCurlCapture_PeetWS(t *testing.T) {
	const helloHex = ""
	const wantJA3Hash = "0149f47eabf9a20d0893e2a44e5a6323"
	const wantJA4 = "t13d3112h2_e8f1e7e78f70_b26ce05bbdd6" // FoxIO-spec-correct; peet.ws reports ..._375ca2c5e164 (drops ext 0x0015)

	raw, err := hex.DecodeString(helloHex)
	if err != nil {
		t.Fatal(err)
	}
	ch, err := ParseClientHello(raw)
	if err != nil {
		t.Fatalf("ParseClientHello on real curl capture: %v", err)
	}
	if got := fmt.Sprintf("%x", md5.Sum([]byte(ch.JA3()))); got != wantJA3Hash {
		t.Errorf("JA3 hash vs peet.ws:\n  got  %s\n  want %s\n  ja3  %s", got, wantJA3Hash, ch.JA3())
	}
	if got := ch.JA4(); got != wantJA4 {
		t.Errorf("JA4 vs FoxIO spec:\n  got  %s\n  want %s", got, wantJA4)
	}
}
